// ---- tokenizer tables ----
#define SZ (1<<17)
static unsigned char tbuf[600000]; static int tlen=0;
static int ktoff[SZ], ktlen[SZ], ktid[SZ];
static int kpoff[SZ], kpll[SZ], kptl[SZ], kprk[SZ];
static int byteid[256], cp2b[400];

static unsigned hh(const unsigned char*p,int n,int salt){unsigned h=2166136261u^salt;for(int i=0;i<n;i++){h^=p[i];h*=16777619u;}return h;}

static int addbuf(const unsigned char*p,int n){int o=tlen;memcpy(tbuf+tlen,p,n);tlen+=n;return o;}

static void tok_put(const unsigned char*p,int n,int id){unsigned i=hh(p,n,0)&(SZ-1);while(ktoff[i]>=0)i=(i+1)&(SZ-1);ktoff[i]=addbuf(p,n);ktlen[i]=n;ktid[i]=id;}
static int tok_get(const unsigned char*p,int n){unsigned i=hh(p,n,0)&(SZ-1);while(ktoff[i]>=0){if(ktlen[i]==n&&!memcmp(tbuf+ktoff[i],p,n))return ktid[i];i=(i+1)&(SZ-1);}return -1;}

static void pr_put(const unsigned char*p,int ll,int tl,int rk){unsigned i=hh(p,tl,ll)&(SZ-1);while(kpoff[i]>=0)i=(i+1)&(SZ-1);kpoff[i]=addbuf(p,tl);kpll[i]=ll;kptl[i]=tl;kprk[i]=rk;}
static int pr_get(const unsigned char*p,int ll,int tl){unsigned i=hh(p,tl,ll)&(SZ-1);while(kpoff[i]>=0){if(kptl[i]==tl&&kpll[i]==ll&&!memcmp(tbuf+kpoff[i],p,tl))return kprk[i];i=(i+1)&(SZ-1);}return -1;}

static void build_tok(const char*bpe){
  memset(ktoff,-1,sizeof ktoff);memset(kpoff,-1,sizeof kpoff);
  // bytes_to_unicode
  int bs[256],cs[256],k=0;
  for(int b=33;b<127;b++){bs[k]=b;cs[k]=b;k++;}
  for(int b=161;b<173;b++){bs[k]=b;cs[k]=b;k++;}
  for(int b=174;b<256;b++){bs[k]=b;cs[k]=b;k++;}
  int n=0;
  for(int b=0;b<256;b++){int f=0;for(int j=0;j<k;j++)if(bs[j]==b){f=1;break;}if(!f){bs[k]=b;cs[k]=256+n;n++;k++;}}
  for(int j=0;j<256;j++){byteid[bs[j]]=j;cp2b[cs[j]]=bs[j];}
  // base tokens
  for(int b=0;b<256;b++){unsigned char c=b;tok_put(&c,1,byteid[b]);}
  // read bpe file
  FILE*fp=fopen(bpe,"rb");fseek(fp,0,SEEK_END);long sz=ftell(fp);fseek(fp,0,SEEK_SET);
  char*buf=malloc(sz+1);fread(buf,1,sz,fp);buf[sz]=0;fclose(fp);
  char*ln=strtok(buf,"\n"); // skip #version
  ln=strtok(NULL,"\n");
  int rank=0;
  unsigned char mm[128];
  while(ln){
    // parse two fields separated by space, UTF-8 -> bytes
    int ml=0,ll=0; int sp=0;
    for(char*q=ln;*q;){
      unsigned char b=*q; int cp;
      if(b==' '){sp=1;ll=ml;q++;continue;}
