static int isL(int c){return isalpha(c);}
static int isN(int c){return isdigit(c);}
static void encode(const char*s){
  int n=strlen(s); int p=0;
  while(p<n){
    unsigned char c=s[p];
    if(c=='\''&&p+1<n){
      char a=s[p+1], b=p+2<n?s[p+2]:0;
      int m=0;
      if((a=='s'||a=='t'||a=='m'||a=='d'))m=2;
      else if((a=='r'&&b=='e')||(a=='v'&&b=='e')||(a=='l'&&b=='l'))m=3;
      if(m){bpe_word((unsigned char*)s+p,m);p+=m;continue;}
    }
    if(isspace(c)){
      int q=p; while(q<n&&isspace((unsigned char)s[q]))q++;
      if(q<n){ // spaces then non-space
        if(q-p>1){bpe_word((unsigned char*)s+p,q-p-1);p=q-1;}
        int st=p; p++; unsigned char d=s[p];
        if(isL(d))while(p<n&&isL((unsigned char)s[p]))p++;
        else if(isN(d))while(p<n&&isN((unsigned char)s[p]))p++;
        else while(p<n&&!isspace((unsigned char)s[p])&&!isL((unsigned char)s[p])&&!isN((unsigned char)s[p]))p++;
        bpe_word((unsigned char*)s+st,p-st);
      } else { bpe_word((unsigned char*)s+p,q-p); p=q; }
    } else {
      int st=p;
      if(isL(c))while(p<n&&isL((unsigned char)s[p]))p++;
      else if(isN(c))while(p<n&&isN((unsigned char)s[p]))p++;
      else while(p<n&&!isspace((unsigned char)s[p])&&!isL((unsigned char)s[p])&&!isN((unsigned char)s[p])&&s[p]!='\'')p++;
      bpe_word((unsigned char*)s+st,p-st);
    }
  }
}

// ---- model ----
static F xb[CTX*E], ab[CTX*E], qkv[CTX*3*E], ao[CTX*E], h1[4*E];
static void lnorm(F*out,F*in,F*g,F*b){
  double m=0; for(int i=0;i<E;i++)m+=in[i]; m/=E;
  double v=0; for(int i=0;i<E;i++){double d=in[i]-m;v+=d*d;} v/=E;
  double s=1.0/sqrt(v+1e-5);
  for(int i=0;i<E;i++)out[i]=(F)((in[i]-m)*s)*g[i]+b[i];
}
static F gelu(F x){return 0.5f*x*(1.f+tanhf(0.7978845608f*(x+0.044715f*x*x*x)));}

static int forward(int*tok,int T){
  F*wte=W, *wpe=W+(long)V*E;
  for(int t=0;t<T;t++)for(int i=0;i<E;i++)xb[t*E+i]=wte[(long)tok[t]*E+i]+wpe[t*E+i];
