    F*ln1g=Lp,*ln1b=Lp+E,*aw=Lp+2*E,*abias=aw+(long)E*3*E,*pw=abias+3*E,*pb=pw+(long)E*E;
    F*ln2g=pb+E,*ln2b=ln2g+E,*fw=ln2b+E,*fb=fw+(long)E*4*E,*mw=fb+4*E,*mb=mw+(long)4*E*E;
    for(int t=0;t<T;t++)lnorm(ab+t*E,xb+t*E,ln1g,ln1b);
    for(int t=0;t<T;t++)for(int j=0;j<3*E;j++){F s=abias[j];F*a=ab+t*E;for(int i=0;i<E;i++)s+=a[i]*aw[(long)i*3*E+j];qkv[t*3*E+j]=s;}
    for(int t=0;t<T;t++)for(int hd=0;hd<H;hd++){
      F sc[CTX]; F mx=-1e30f;
      F*q=qkv+t*3*E+hd*HD;
      for(int t2=0;t2<=t;t2++){F*kk=qkv+t2*3*E+E+hd*HD;F d=0;for(int i=0;i<HD;i++)d+=q[i]*kk[i];d/=8.f;sc[t2]=d;if(d>mx)mx=d;}
      F sm=0;for(int t2=0;t2<=t;t2++){sc[t2]=expf(sc[t2]-mx);sm+=sc[t2];}
      for(int i=0;i<HD;i++){F acc=0;for(int t2=0;t2<=t;t2++){F*vv=qkv+t2*3*E+2*E+hd*HD;acc+=sc[t2]/sm*vv[i];}ao[t*E+hd*HD+i]=acc;}
    }
    for(int t=0;t<T;t++)for(int j=0;j<E;j++){F s=pb[j];F*a=ao+t*E;for(int i=0;i<E;i++)s+=a[i]*pw[(long)i*E+j];xb[t*E+j]+=s;}
    for(int t=0;t<T;t++){
      lnorm(ab+t*E,xb+t*E,ln2g,ln2b);
      for(int j=0;j<4*E;j++){F s=fb[j];F*a=ab+t*E;for(int i=0;i<E;i++)s+=a[i]*fw[(long)i*4*E+j];h1[j]=gelu(s);}
      for(int j=0;j<E;j++){F s=mb[j];for(int i=0;i<4*E;i++)s+=h1[i]*mw[(long)i*E+j];xb[t*E+j]+=s;}
    }
