static int tok_get(const unsigned char*p,int n){unsigned i=hh(p,n,0)&(SZ-1);while(ktoff[i]>=0){if(ktlen[i]==n&&!memcmp(tbuf+ktoff[i],p,n))return ktid[i];i=(i+1)&(SZ-1);}return -1;}
