static int pr_get(const unsigned char*p,int ll,int tl){unsigned i=hh(p,tl,ll)&(SZ-1);while(kpoff[i]>=0){if(kptl[i]==tl&&kpll[i]==ll&&!memcmp(tbuf+kpoff[i],p,tl))return kprk[i];i=(i+1)&(SZ-1);}return -1;}
static void build_tok(const char*bpe){
  memset(ktoff,-1,sizeof ktoff);memset(kpoff,-1,sizeof kpoff);
